    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

// Custom debounce hook. Returns the debounced value plus a flag that's true
// while a new value is "pending" (i.e. during the 300ms delay window).
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);

    useEffect(() => {
        // Value changed but not yet committed -> we're debouncing.
        setIsPending(true);
        const timeoutId = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Cleanup clears the pending timeout on value change AND on unmount,
        // preventing state updates on an unmounted component (no memory leak).
        return () => clearTimeout(timeoutId);
    }, [value, delay]);

    return [debouncedValue, isPending];
}

// Escape characters that have special meaning in a RegExp so user input
// like "C++" or "(data)" can't throw or behave unexpectedly.
function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Split `text` around case-insensitive matches of `query` and wrap matches
// in <mark>. Returns an array of React nodes.
function highlightMatch(text, query) {
    if (!query) return text;

    const escaped = escapeRegExp(query);
    // Capturing group so split() keeps the matched segments.
    const parts = text.split(new RegExp(`(${escaped})`, 'gi'));

    return parts.map((part, index) =>
        part.toLowerCase() === query.toLowerCase() ? (
            <mark key={index}>{part}</mark>
        ) : (
            <React.Fragment key={index}>{part}</React.Fragment>
        )
    );
}

function ResourceList() {
