 * useDebounce
 *
 * Returns:
 *   debouncedValue – the value after the delay has elapsed.
 *   isPending      – true while a timer is running (derived, not extra state).
 *
 * Special cases handled here so callers don't have to repeat them:
 *   • Whitespace-only input is normalised to "" immediately (no delay).
 *   • The timer is cancelled both when `value` changes AND on unmount,
 *     preventing stale-closure updates and memory leaks.
 */
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    // Treat whitespace-only as empty — sync immediately, no debounce needed.
    if (value.trim() === '') {
      setDebouncedValue('');
      return; // no timer to clean up
    }

    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    // ← Runs when `value` changes (cancels the previous timer) OR on unmount.
    return () => clearTimeout(timer);
